create table if not exists projects(id serial primary key,name text not null,created_at timestamptz default now());create table if not exists pages(id serial primary key,project_id int references projects(id) on delete cascade,name text not null,position integer not null default 1,scene jsonb default '{}'::jsonb,created_at timestamptz default now(),updated_at timestamptz default now());insert into projects(name) select 'Inbox' where not exists(select 1 from projects);insert into pages(project_id,name,position) select id,'Untitled canvas',1 from projects where name='Inbox' and not exists(select 1 from pages);
